"""Секция [CORE] в app.ini."""from __future__ import annotationsfrom dataclasses import dataclass, field@dataclass(frozen=True)class CoreConfig:    """Секция [CORE] в app.ini."""    debug: bool = False    log_level: str = field(default="DEBUG", metadata={"ini_key": "LEVEL"})    console_log_level: str = field(default="INFO", metadata={"ini_key": "CONSOLE_LEVEL"})    language: str = field(default="", metadata={"ini_key": "LANGUAGE"})